#include <stdio.h>
#include <stdlib.h>
#include <time.h>

void log_error(FILE* logfile, const char* error_msg, const char* file, int line, const char* function) {
    time_t now;
    time(&now);
    
    fprintf(logfile, "[%s] ERROR in %s:%d in function %s: %s\n", 
            ctime(&now), file, line, function, error_msg);
}

void log_error_with_data(FILE* logfile, const char* format, const char* file, int line, const char* function, ...) {
    time_t now;
    time(&now);
    
    fprintf(logfile, "[%s] ERROR in %s:%d in function %s: ", 
            ctime(&now), file, line, function);
    
    va_list args;
    va_start(args, function);
    vfprintf(logfile, format, args);
    va_end(args);
    
    fprintf(logfile, "\n");
}